// ── Utility helpers ───────────────────────────────────────────────

export const poemsByCategory = (category: string): Poem[] =>
  poemData.filter((p) => p.category === category);

export const poemsByAuthor = (author: string): Poem[] =>
  poemData.filter((p) =>
    p.author.toLowerCase().includes(author.toLowerCase())
  );

export const searchPoems = (query: string): Poem[] => {
  const q = query.toLowerCase();
  return poemData.filter(
    (p) =>
      p.title.toLowerCase().includes(q) ||
      p.author.toLowerCase().includes(q) ||
      (p.summary?.toLowerCase().includes(q) ?? false) ||
      (p.facts?.toLowerCase().includes(q) ?? false)
  );
};

export const uniqueAuthors = (): string[] =>
  [...new Set(poemData.map((p) => p.author))].sort();

export const categoryCounts = (): Record<PoemCategory, number> => ({
  British:  poemsByCategory("British").length,
  American: poemsByCategory("American").length,
  Indian:   poemsByCategory("Indian").length,
  World:    poemsByCategory("World").length,
});

export default poemData;
